#!/usr/bin/env node
import { stdin as input } from "node:process";
import { renderPngBase64, renderPngDataUrl, renderSvg, renderTerminal, renderUtf8, writePngFile, writeSvgFile, } from "./index.js";
import { normalizeCliText } from "./shared.js";
function printHelp() {
    process.stdout.write([
        "qrcode-tui <text> [options]",
        "",
        "Options:",
        "  --type <type>  terminal | utf8 | png-base64 | png-data-url | svg",
        "  --out <path>   Write PNG or SVG to disk (extension or --type decides)",
        "  --width <n>    Set output width",
        "  --scale <n>    Set PNG scale",
        "  --margin <n>   Set quiet-zone margin",
        "  --error-correction <L|M|Q|H>  Set error correction level",
        "  --utf8         Shortcut for --type utf8",
        "  --svg          Shortcut for --type svg",
        "  --png-base64   Shortcut for --type png-base64",
        "  --png-data-url Shortcut for --type png-data-url",
        "  --no-small     Disable compact terminal output for terminal mode",
        "  -h, --help     Show help",
        "",
        "You can also pipe text in on stdin.",
        "",
    ].join("\n"));
}
function parseArgs(argv) {
    const options = { small: true };
    const textParts = [];
    for (let index = 0; index < argv.length; index += 1) {
        const arg = argv[index];
        if (arg === "-h" || arg === "--help") {
            printHelp();
            process.exit(0);
        }
        if (arg === "--type") {
            options.type = argv[index + 1];
            index += 1;
            continue;
        }
        if (arg === "--utf8") {
            options.type = "utf8";
            continue;
        }
        if (arg === "--svg") {
            options.type = "svg";
            continue;
        }
        if (arg === "--png-base64") {
            options.type = "png-base64";
            continue;
        }
        if (arg === "--png-data-url") {
            options.type = "png-data-url";
            continue;
        }
        if (arg === "--no-small") {
            options.small = false;
            continue;
        }
        if (arg === "--out") {
            options.outputPath = argv[index + 1];
            index += 1;
            continue;
        }
        if (arg === "--width") {
            options.width = Number(argv[index + 1]);
            index += 1;
            continue;
        }
        if (arg === "--scale") {
            options.scale = Number(argv[index + 1]);
            index += 1;
            continue;
        }
        if (arg === "--margin") {
            options.margin = Number(argv[index + 1]);
            index += 1;
            continue;
        }
        if (arg === "--error-correction") {
            options.errorCorrectionLevel = argv[index + 1];
            index += 1;
            continue;
        }
        if (arg.startsWith("-")) {
            throw new Error(`Unknown argument: ${arg}`);
        }
        textParts.push(arg);
    }
    return {
        options,
        text: textParts.length > 0 ? textParts.join(" ") : undefined,
    };
}
async function readStdinIfPresent() {
    if (input.isTTY) {
        return undefined;
    }
    const chunks = [];
    for await (const chunk of input) {
        chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
    }
    if (chunks.length === 0) {
        return undefined;
    }
    const text = Buffer.concat(chunks).toString("utf8").trimEnd();
    return text.length > 0 ? text : undefined;
}
function inferFileOutputType(params) {
    if (params.type === "svg") {
        return "svg-file";
    }
    if (params.outputPath.toLowerCase().endsWith(".svg")) {
        return "svg-file";
    }
    return "png-file";
}
function validateOptions(options) {
    if (options.type &&
        !["png-base64", "png-data-url", "svg", "terminal", "utf8"].includes(options.type)) {
        throw new Error(`Unsupported --type '${options.type}'.`);
    }
    if (options.errorCorrectionLevel &&
        !["L", "M", "Q", "H"].includes(options.errorCorrectionLevel)) {
        throw new Error(`Unsupported --error-correction '${options.errorCorrectionLevel}'.`);
    }
    for (const [label, value] of [
        ["width", options.width],
        ["scale", options.scale],
        ["margin", options.margin],
    ]) {
        if (value !== undefined && (!Number.isFinite(value) || value < 0)) {
            throw new Error(`--${label} must be a non-negative number.`);
        }
    }
}
async function main() {
    const { options, text: textFromArgs } = parseArgs(process.argv.slice(2));
    validateOptions(options);
    const stdinText = textFromArgs === undefined ? await readStdinIfPresent() : undefined;
    const text = textFromArgs ?? stdinText;
    if (!text) {
        printHelp();
        process.exitCode = 1;
        return;
    }
    const normalizedText = normalizeCliText(text);
    const sharedOptions = {
        errorCorrectionLevel: options.errorCorrectionLevel,
        margin: options.margin,
        scale: options.scale,
        width: options.width,
    };
    if (options.outputPath) {
        const outputType = inferFileOutputType({
            outputPath: options.outputPath,
            type: options.type,
        });
        const filePath = outputType === "svg-file"
            ? await writeSvgFile(normalizedText, options.outputPath, sharedOptions)
            : await writePngFile(normalizedText, options.outputPath, sharedOptions);
        process.stdout.write(`${filePath}\n`);
        return;
    }
    let output;
    switch (options.type ?? "terminal") {
        case "png-base64":
            output = await renderPngBase64(normalizedText, sharedOptions);
            break;
        case "png-data-url":
            output = await renderPngDataUrl(normalizedText, sharedOptions);
            break;
        case "svg":
            output = await renderSvg(normalizedText, sharedOptions);
            break;
        case "utf8":
            output = await renderUtf8(normalizedText, sharedOptions);
            break;
        case "terminal":
            output = await renderTerminal(normalizedText, { ...sharedOptions, small: options.small });
            break;
    }
    process.stdout.write(output.endsWith("\n") ? output : `${output}\n`);
}
await main().catch((error) => {
    const message = error instanceof Error ? error.message : String(error);
    process.stderr.write(`${message}\n`);
    process.exitCode = 1;
});
